#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e5+10;
long long a[MAXN];
map<long long,long long>m;
int main()
{
	int n;
	cin>>n;
	int mini=1e9+7;
	for(int i = 0; i < n; i++){
		cin >> a[i];
		if(a[i] > mini) m[a[i]]++;
		else mini=a[i];
	}
	long long cnt = 1;
	for(auto u:m){
		int w = u.second;
//		cout << u.first << " " << u.second<<endl;
		cnt *= (w + 1);
		cnt %= 998244353;
	}
	cout << cnt;  
}
